#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "").strip()

    # Block bare "pnpm test" (interactive watcher)
    # Allow "pnpm test:ci" or any other variant
    if cmd.startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Read":
        return 0

    file_path = inp.get("file_path", "")
    basename = os.path.basename(file_path)

    # Block reads of .env files (secrets are in .env.local; .env could contain examples)
    # Allow .env.example, .env.template, etc. (safe documentation)
    is_blocked = (
        basename == ".env" or
        basename == ".env.local" or
        (basename.startswith(".env.") and basename.endswith(".local"))
    )
    if is_blocked:
        msg = f"REQUIRED FOLLOW-UP: Reading .env files (like {basename}) is blocked to prevent accidental exposure of secrets. Examine .env.example instead if needed."
        print(msg, file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

