import json
import sys
import subprocess
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    if ev.get("hook_event_name", "") != "Stop":
        return 0

    try:
        # Get diff of staged + unstaged changes
        diff = subprocess.check_output(
            ["git", "diff", "HEAD"],
            text=True,
            stderr=subprocess.DEVNULL
        )
    except Exception:
        return 0

    # Only check src/tree.py
    if 'src/tree.py' not in diff:
        return 0

    # Extract lines being added (start with '+' but not '+++')
    added_lines = '\n'.join(
        line[1:] for line in diff.split('\n')
        if line.startswith('+') and not line.startswith('+++')
    )

    # Find all function definitions in the additions
    func_defs = re.findall(r'def\s+(\w+)\s*\(', added_lines)

    for func_name in func_defs:
        # Check if function calls itself (recursive)
        if f'{func_name}(' in added_lines:
            print(
                f"BLOCKING: Recursive function '{func_name}' detected in src/tree.py. "
                f"This tree-walking codebase requires iterative implementations to handle large inputs safely. "
                f"REQUIRED FOLLOW-UP: Refactor using iterative approach (e.g., worklist pattern).",
                file=sys.stderr
            )
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

