#!/usr/bin/env python3
import json
import sys
import subprocess
import re
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    if tool != "Edit":
        return 0

    inp = ev.get("tool_input", {}) or {}
    file_path = inp.get("file_path", "")
    old_string = inp.get("old_string", "")
    new_string = inp.get("new_string", "")

    # Only process TypeScript files with exports
    if not file_path or not file_path.endswith((".ts", ".tsx")):
        return 0

    if "export" not in old_string or "export" not in new_string:
        return 0

    # Extract exported const declarations: export const NAME = 'value'
    old_match = re.search(r"export\s+const\s+(\w+)\s*=\s*['\"]([^'\"]+)['\"]", old_string)
    new_match = re.search(r"export\s+const\s+(\w+)\s*=\s*['\"]([^'\"]+)['\"]", new_string)

    if not (old_match and new_match):
        return 0

    old_id, old_val = old_match.groups()
    new_id, new_val = new_match.groups()

    # Only alert if the VALUE changed (not just the identifier name)
    if old_val == new_val:
        return 0

    # Search for references to the old value
    try:
        result = subprocess.run(
            ["grep", "-r", old_val, "--include=*.ts", "--include=*.tsx",
             "--include=*.js", "--include=*.jsx", "."],
            capture_output=True,
            text=True,
            timeout=10
        )

        if result.stdout:
            lines = result.stdout.strip().split("\n")
            matching_refs = [l for l in lines if l and old_val in l]

            if matching_refs:
                print(f"BLOCKING: Exported identifier '{old_id}' value changed from '{old_val}' to '{new_val}'.", file=sys.stderr)
                print("Do not stop. Fix each hardcoded reference below:", file=sys.stderr)
                for line in matching_refs[:25]:
                    print(line, file=sys.stderr)
                if len(matching_refs) > 25:
                    print(f"... and {len(matching_refs) - 25} more matches.", file=sys.stderr)
                return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check Edit and Write tools
    if tool not in ("Edit", "Write"):
        return 0

    # Get the content to check
    content_to_check = ""
    if tool == "Write":
        content_to_check = inp.get("content", "")
    elif tool == "Edit":
        content_to_check = inp.get("new_string", "")

    if not content_to_check:
        return 0

    # Get file path
    file_path = inp.get("file_path", "")

    # Skip .env files (these are meant to document env vars)
    if any(file_path.endswith(x) for x in (".env", ".env.example", ".env.local", ".env.sample")):
        return 0

    # Patterns that indicate secrets
    secret_patterns = [
        r'sk-proj-[a-zA-Z0-9]+',  # OpenAI API key
        r'sk-[a-zA-Z0-9]{30,}',  # Stripe/Anthropic secret key (long)
        r'AKIA[0-9A-Z]{16}',  # AWS Access Key
        r'-----BEGIN (?:RSA |OPENSSH )?PRIVATE KEY',  # Private keys
        # Quoted secret values (with negative lookahead for env var references)
        r'(?:api[_-]?key|apiKey|password|token)\s*[:=]\s*["\'](?!process\.env\.|import\.meta\.env\.)[a-zA-Z0-9\-_.]{8,}["\']',
    ]

    for pattern in secret_patterns:
        if re.search(pattern, content_to_check, re.IGNORECASE):
            msg = f"BLOCKING: {file_path} appears to contain a hardcoded secret (API key, token, password, or private key). REQUIRED FOLLOW-UP: Secrets must come from environment variables. See CLAUDE.md: 'Secrets come from the environment.'"
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")

    if "git commit" not in command or "-m" not in command:
        return 0

    # Extract message from -m "..." or -m '...'
    msg = None
    match = re.search(r'-m\s*"([^"]*)"', command)
    if match:
        msg = match.group(1)
    else:
        match = re.search(r"-m\s*'([^']*)'", command)
        if match:
            msg = match.group(1)

    if not msg:
        return 0

    # Check for paragraph format (multiple sentences)
    if '. ' in msg:
        print("Commit message should be a single imperative line (e.g., 'Refactor auth: extract token validation'), not a paragraph.", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

